 1	import * as React from 'react';
 2	import { getLastAppDeploymentClusterName } from '@odf/mco/utils';
 3	import { useCustomTranslation } from '@odf/shared';
 4	import { ModalFooter } from '@odf/shared/modals';
 5	import {
 6	  useK8sWatchResources,
 7	  WatchK8sResource,
 8	} from '@openshift-console/dynamic-plugin-sdk';
 9	import { Button, ButtonVariant } from '@patternfly/react-core';
10	import {
11	  buildMCVResource,
12	  ConsistencyGroupsContent,
13	  extractConsistencyGroups,
14	  getMCVName,
15	  WatchResourceType,
16	} from './helper/consistency-groups';
17	import { ModalViewContext } from './utils/reducer';
18	import { DRInfoType } from './utils/types';
19	
20	type VolumeConsistencyGroupViewProps = {
21	  setModalContext: (context: ModalViewContext) => void;
22	  drInfo?: DRInfoType;
23	};
24	
25	export const VolumeConsistencyGroupView: React.FC<
26	  VolumeConsistencyGroupViewProps
27	> = ({ setModalContext, drInfo }) => {
28	  const { t } = useCustomTranslation();
29	  const mcvResources = React.useMemo(() => {
30	    const resources: Record<string, WatchK8sResource> = {};
31	
32	    if (drInfo?.placementControlInfo) {
33	      drInfo.placementControlInfo.forEach((placementControl) => {
34	        const clusterName = getLastAppDeploymentClusterName(placementControl);
35	
36	        if (clusterName) {
37	          const mcvName = getMCVName(placementControl);
38	          resources[mcvName] = buildMCVResource(clusterName, mcvName);
39	        }
40	      });
41	    }
42	
43	    return resources;
44	  }, [drInfo]);
45	
46	  const mcvs = useK8sWatchResources<WatchResourceType>(mcvResources);
47	  const {
48	    data: consistencyGroups,
49	    loaded,
50	    loadError,
51	  } = extractConsistencyGroups(mcvs);
52	
53	  return (
54	    <>
55	      <ConsistencyGroupsContent
56	        consistencyGroups={consistencyGroups}
57	        loaded={loaded}
58	        loadError={loadError}
59	      />
60	      <ModalFooter>
61	        <Button
62	          variant={ButtonVariant.secondary}
63	          onClick={() => setModalContext(ModalViewContext.MANAGE_POLICY_VIEW)}
64	        >
65	          {t('Go back')}
66	        </Button>
67	      </ModalFooter>
68	    </>
69	  );
70	};

